class Solution:
    def evenOddBit(self, n: int) -> List[int]:
        even, odd = 0, 0
        index = 0
        while n:
            if n & 1:
                if index % 2 == 0:
                    even += 1
                else:
                    odd += 1
            n >>= 1
            index += 1
        return [even, odd]

